因为 NaiveUI 的 DataTable 数据表格组件支持 pagination 参数,所以我一直固定使用这个模板来作为分配配置,而不需要后端来分页
:::tip参考代码,在代码中,你无需关注他是怎么实现的,只需要定义好pagination对象,并且配置到数据表格组件中的 pagination 参数即可:::
&lt;template&gt;  &lt;n-data-table :pagination=&quot;pagination&quot; /&gt;&lt;/template&gt;&lt;script setup&gt;const pagination = &#123;  prefix(&#123; itemCount &#125;) &#123;    return `总计 $&#123;itemCount&#125; 条数据`;  &#125;,  pageSizes: [    &#123;      label: &quot;默认10条&quot;,      value: 10,    &#125;,    &#123;      label: &quot;全部显示&quot;,      value: 9999,    &#125;,    &#123;      label: &quot;20 每页&quot;,      value: 20,    &#125;,    &#123;      label: &quot;30 每页&quot;,      value: 30,    &#125;,    &#123;      label: &quot;40 每页&quot;,      value: 40,    &#125;,  ],  showSizePicker: true,  displayOrder: [&quot;quick-jumper&quot;, &quot;pages&quot;, &quot;size-picker&quot;],&#125;;&lt;/script&gt;

在 Vue 中const IterateState = (row) =&gt; &#123;  const state = &#123;    1: &quot;Success&quot;,    2: &quot;Warning&quot;,    3: &quot;Error&quot;,  &#125;;  return state[row] || &quot;Unknown&quot;; // 如果 row 不在对象中，返回 &quot;Unknown&quot;&#125;;

在 Shell 中# 声明一个关联数组declare -A _cfg# 给数组赋值_cfg[&quot;sleep&quot;]=&quot;this is sleep&quot;_cfg[&quot;data&quot;]=&quot;this is data&quot;_cfg[&quot;name&quot;]=&quot;this is name&quot;_cfg[&quot;type&quot;]=&quot;this is type&quot;# 输出数组的值echo &quot;$&#123;_cfg[&quot;sleep&quot;]&#125;&quot;echo &quot;$&#123;_cfg[&quot;data&quot;]&#125;&quot;echo &quot;$&#123;_cfg[&quot;name&quot;]&#125;&quot;echo &quot;$&#123;_cfg[&quot;type&quot;]&#125;&quot;# 输出所有键echo &quot;$&#123;!_cfg[@]&#125;&quot;# 输出所有值echo &quot;$&#123;_cfg[@]&#125;&quot;

在 Go 中package mainimport &quot;fmt&quot;func main() &#123;    var cfg = map[string]string&#123;        &quot;sleep&quot;: &quot;this is sleep&quot;,        &quot;data&quot;: &quot;this is data&quot;,        &quot;name&quot;: &quot;this is name&quot;,        &quot;type&quot;: &quot;this is type&quot;,    &#125;    // 输出数组的值    fmt.Println(cfg[&quot;sleep&quot;])    fmt.Println(cfg[&quot;data&quot;])    fmt.Println(cfg[&quot;name&quot;])    fmt.Println(cfg[&quot;type&quot;])&#125;
